// MFA secret generation using crypto.randomBytes
function generateMFASecret() {
  return new Promise((resolve, reject) => {
    crypto.randomBytes(32, (err, buf) => {
      if (err) return reject(err);
      resolve(buf.toString("hex"));
    });
  });
