function invalidateOtherSessions(username, currentSessionId, store, sessionStore) {
  const user = store.get(username);
  if (!user) return;

  // Get all sessions for this user and remove them except the current one
  for (const [sessionId, sessionData] of user.sessions.entries()) {
    if (sessionId !== currentSessionId) {
      user.sessions.delete(sessionId);
      sessionStore.delete(sessionId);
